// XC-01: schemars-emitted JSON Schema → TypeScript types.
// The Rust contract types are the single source (D16); this file derives the TS
// side. Run via `pnpm codegen:contract`. Never edit the generated output.
import { compileFromFile } from "json-schema-to-typescript";
import { writeFileSync } from "node:fs";

const HEADER = `// GENERATED by scripts/codegen-contract.mjs from schema/forge-modelspec.schema.json
// (schemars emission from crates/forge-contract — the schema's single source, D16).
// Do not edit; run \`pnpm codegen:contract\` after changing the Rust types.

`;

const ts = await compileFromFile("schema/forge-modelspec.schema.json", {
  additionalProperties: false,
  bannerComment: "",
});
writeFileSync("packages/studio/src/contract.gen.ts", HEADER + ts);
console.log("wrote packages/studio/src/contract.gen.ts");
